#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-06

# =============================================================================
# stamp-counts.sh — Replace count markers with canonical values
# =============================================================================
# Replaces <!--ork:KEY-->OLD<!--/ork--> markers in markdown files and updates
# JSON files with current component counts. Run as part of build.
#
# Canonical sources:
#   Skills:  src/skills/*/SKILL.md count
#   Agents:  src/agents/*.md count
#   Hooks:   bin/count-hooks.sh
#
# Usage:
#   bash scripts/stamp-counts.sh          # stamp all files
#   bash scripts/stamp-counts.sh --check  # exit 1 if any file is stale
# =============================================================================

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)"

# ── Compute canonical counts ────────────────────────────────────────────────

SKILLS=$(find "$PROJECT_ROOT/src/skills" -mindepth 1 -maxdepth 1 -type d -not -name shared | wc -l | tr -d ' ')
AGENTS=$(find "$PROJECT_ROOT/src/agents" -maxdepth 1 -name '*.md' | grep -viE '/(README|INDEX|CONTRIBUTING)\.md$' | wc -l | tr -d ' ')
eval "$("$PROJECT_ROOT/bin/count-hooks.sh")"
HOOKS=$TOTAL  # TOTAL set by count-hooks.sh
HOOKS_GLOBAL=$GLOBAL
HOOKS_AGENT=$AGENT
HOOKS_SKILL=$SKILL

# User-invocable skills count
INVOCABLE=$(grep -rl '^user-invocable: true' "$PROJECT_ROOT/src/skills/" --include='SKILL.md' 2>/dev/null | wc -l | tr -d ' ')

# ── Marker replacement ──────────────────────────────────────────────────────

# Replace <!--ork:KEY-->VALUE<!--/ork--> with updated VALUE
stamp_marker() {
  local file="$1"
  local key="$2"
  local value="$3"

  if [[ ! -f "$file" ]]; then
    return
  fi

  # macOS sed needs '' after -i, Linux doesn't
  if [[ "$(uname)" == "Darwin" ]]; then
    sed -i '' -E "s/(<!--ork:${key}-->)[0-9]+(<!--\\/ork-->)/\\1${value}\\2/g" "$file"
  else
    sed -i -E "s/(<!--ork:${key}-->)[0-9]+(<!--\\/ork-->)/\\1${value}\\2/g" "$file"
  fi
}

# Stamp all markers in a file
stamp_file() {
  local file="$1"
  stamp_marker "$file" "skills" "$SKILLS"
  stamp_marker "$file" "agents" "$AGENTS"
  stamp_marker "$file" "hooks" "$HOOKS"
  stamp_marker "$file" "hooks-global" "$HOOKS_GLOBAL"
  stamp_marker "$file" "hooks-agent" "$HOOKS_AGENT"
  stamp_marker "$file" "hooks-skill" "$HOOKS_SKILL"
  stamp_marker "$file" "invocable" "$INVOCABLE"
}

# ── Files with markers ──────────────────────────────────────────────────────

MARKER_FILES=(
  "$PROJECT_ROOT/README.md"
  "$PROJECT_ROOT/CLAUDE.md"
  "$PROJECT_ROOT/CONTRIBUTING.md"
  "$PROJECT_ROOT/src/hooks/README.md"
)
# NOTE: Do NOT add files under src/skills/ — they get copied into MDX where
# HTML comments are escaped as &lt;!-- and break rendering.

# ── JSON updates (no markers, pattern-based) ────────────────────────────────

stamp_marketplace_json() {
  local file="$PROJECT_ROOT/.claude-plugin/marketplace.json"
  if [[ ! -f "$file" ]]; then return; fi

  local sed_in
  if [[ "$(uname)" == "Darwin" ]]; then
    sed_in=(sed -i '' -E)
  else
    sed_in=(sed -i -E)
  fi

  # Top-level description: "X skills, Y agents, Z commands, N hooks"
  "${sed_in[@]}" \
    "s/[0-9]+ skills, [0-9]+ agents, [0-9]+ commands, [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, ${INVOCABLE} commands, ${HOOKS} hooks/g" "$file"

  # plugins[].description: "X skills covering ... Includes Y specialized agents, Z commands, and N lifecycle hooks."
  "${sed_in[@]}" \
    "s/[0-9]+ skills covering/${SKILLS} skills covering/g" "$file"
  "${sed_in[@]}" \
    "s/Includes [0-9]+ specialized agents, [0-9]+ commands, and [0-9]+ lifecycle hooks/Includes ${AGENTS} specialized agents, ${INVOCABLE} commands, and ${HOOKS} lifecycle hooks/g" "$file"

  # Legacy variant (no commands count) — kept for backwards compat
  "${sed_in[@]}" \
    "s/[0-9]+ skills, [0-9]+ agents, [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, ${HOOKS} hooks/g" "$file"
}

# ── pyproject.toml description (count tuple, pattern-based) ──────────────────
# sync_versions() owns the `version = "..."` line; this owns the component-count
# tuple in the `description` string. It was the one count string no stamper
# touched, so it silently drifted (105/180 vs actual). The build runs this, and
# the plugins/ drift gate transitively enforces it: any count change also
# changes plugins/, forcing a rebuild that re-stamps this. Single phrasing only.
stamp_pyproject_description() {
  local file="$PROJECT_ROOT/pyproject.toml"
  if [[ ! -f "$file" ]]; then return; fi

  local sed_in
  if [[ "$(uname)" == "Darwin" ]]; then
    sed_in=(sed -i '' -E)
  else
    sed_in=(sed -i -E)
  fi

  # "with N skills, M agents, and K hooks"
  "${sed_in[@]}" \
    "s/[0-9]+ skills, [0-9]+ agents, and [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, and ${HOOKS} hooks/g" "$file"
}

# ── manifests/ork.json description (count tuple) ────────────────────────────
# build-plugins.sh copies this .description verbatim into the generated
# plugins/ork/.claude-plugin/plugin.json, which bin/validate-counts.sh reads.
# Retiring bin/update-counts.sh (#2606) removed the only stamper of this string,
# leaving it to drift until the first count change (adding a skill) exposed it.
stamp_ork_manifest_description() {
  local file="$PROJECT_ROOT/manifests/ork.json"
  if [[ ! -f "$file" ]]; then return; fi
  local desc
  desc=$(jq -r '.description' "$file")
  # "N skills, M agents, K hooks" (no "and") — the marketplace/plugin phrasing
  local new
  new=$(printf '%s' "$desc" | sed -E "s/[0-9]+ skills, [0-9]+ agents, [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, ${HOOKS} hooks/g")
  if [[ "$new" != "$desc" ]]; then
    jq --arg d "$new" '.description = $d' "$file" > "${file}.tmp" && mv "${file}.tmp" "$file"
  fi
}

# ── CLAUDE.md plain directory-structure count comment ───────────────────────
# Line: "skills/<name>/SKILL.md    # N skills (YAML ...)" — plain text, not a
# marker, so stamp_file() misses it. Tight anchor avoids unrelated numbers.
stamp_claudemd_plain_count() {
  local file="$PROJECT_ROOT/CLAUDE.md"
  if [[ ! -f "$file" ]]; then return; fi
  local sed_in
  if [[ "$(uname)" == "Darwin" ]]; then sed_in=(sed -i '' -E); else sed_in=(sed -i -E); fi
  "${sed_in[@]}" "s/# [0-9]+ skills \\(YAML/# ${SKILLS} skills (YAML/g" "$file"
}

# ── docs/site MDX (pattern-based, no markers) ───────────────────────────────
# MDX renders HTML comments literally, so the marker approach used for
# README/CLAUDE.md doesn't work here. Instead we replace explicit, safe
# phrasings. Add new patterns as new phrasings appear; keep them tight to
# avoid hitting unrelated numbers (file sizes, percentages, code samples).
apply_docs_mdx_patterns() {
  local file="$1"
  local sed_in
  if [[ "$(uname)" == "Darwin" ]]; then
    sed_in=(sed -i '' -E)
  else
    sed_in=(sed -i -E)
  fi

  # Three-tuple "X skills, Y agents, Z hooks" (with or without "and")
  "${sed_in[@]}" "s/[0-9]+ skills, [0-9]+ agents, and [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, and ${HOOKS} hooks/g" "$file"
  "${sed_in[@]}" "s/[0-9]+ skills, [0-9]+ agents, [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, ${HOOKS} hooks/g" "$file"
  "${sed_in[@]}" "s/[0-9]+ skills and [0-9]+ agents/${SKILLS} skills and ${AGENTS} agents/g" "$file"

  # All patterns below MUST be unambiguous about referring to the OrchestKit total.
  # Generic phrasings like "All N skills", "Agents (N)", "Hooks (N)", "[Category] Hooks (N)",
  # "Total | **N**" are intentionally NOT included — they catch workflow sub-counts,
  # category breakdowns, and unrelated table totals (analytics tables, sample JSON specs).
  # When a new total-count phrasing appears in a doc, add it here EXPLICITLY.

  # Skills-specific
  "${sed_in[@]}" "s/OrchestKit's [0-9]+ skills/OrchestKit's ${SKILLS} skills/g" "$file"
  "${sed_in[@]}" "s/title=\"[0-9]+ Skills\"/title=\"${SKILLS} Skills\"/g" "$file"
  "${sed_in[@]}" "s/All [0-9]+ command skills/All ${INVOCABLE} command skills/g" "$file"
  "${sed_in[@]}" "s/[0-9]+ command skills \\(user-invocable/${INVOCABLE} command skills (user-invocable/g" "$file"
  "${sed_in[@]}" "s/dependency edges across connected skills \\(out of [0-9]+ total\\)/dependency edges across connected skills (out of ${SKILLS} total)/g" "$file"
  "${sed_in[@]}" "s/### Skills \\([0-9]+\\) inject/### Skills (${SKILLS}) inject/g" "$file"

  # Agents-specific
  "${sed_in[@]}" "s/OrchestKit includes \\*\\*[0-9]+ specialized agents/OrchestKit includes **${AGENTS} specialized agents/g" "$file"
  "${sed_in[@]}" "s/^# [0-9]+ Specialists,/# ${AGENTS} Specialists,/g" "$file"
  "${sed_in[@]}" "s/all [0-9]+ existing agents/all ${AGENTS} existing agents/g" "$file"
  "${sed_in[@]}" "s/^## The [0-9]+ Agents by Category/## The ${AGENTS} Agents by Category/g" "$file"
  "${sed_in[@]}" "s/### Agents \\([0-9]+\\) activate/### Agents (${AGENTS}) activate/g" "$file"
  "${sed_in[@]}" "s/OrchestKit's [0-9]+ agents/OrchestKit's ${AGENTS} agents/g" "$file"
  "${sed_in[@]}" "s/^Agents:[[:space:]]+[0-9]+ registered/Agents:     ${AGENTS} registered/g" "$file"
  "${sed_in[@]}" "s/title=\"[0-9]+ Agents\"/title=\"${AGENTS} Agents\"/g" "$file"
  "${sed_in[@]}" "s/Complete reference for all [0-9]+ OrchestKit agents/Complete reference for all ${AGENTS} OrchestKit agents/g" "$file"

  # Hooks-specific
  "${sed_in[@]}" "s/[0-9]+ Hooks: What Fires When/${HOOKS} Hooks: What Fires When/g" "$file"
  "${sed_in[@]}" "s/OrchestKit's [0-9]+ hooks/OrchestKit's ${HOOKS} hooks/g" "$file"
  "${sed_in[@]}" "s/consolidates [0-9]+ hooks/consolidates ${HOOKS} hooks/g" "$file"
  "${sed_in[@]}" "s/compiles [0-9]+ hooks/compiles ${HOOKS} hooks/g" "$file"
  "${sed_in[@]}" "s/With [0-9]+ hooks,/With ${HOOKS} hooks,/g" "$file"
  "${sed_in[@]}" "s/All [0-9]+ hooks are written in TypeScript/All ${HOOKS} hooks are written in TypeScript/g" "$file"
  "${sed_in[@]}" "s/[0-9]+ hooks across [0-9]+ categories/${HOOKS} hooks across 12 categories/g" "$file"
  "${sed_in[@]}" "s/[0-9]+ hooks active/${HOOKS} hooks active/g" "$file"
  "${sed_in[@]}" "s/[0-9]+ global hook entries/${HOOKS_GLOBAL} global hook entries/g" "$file"
  "${sed_in[@]}" "s/### Hooks \\([0-9]+\\) fire/### Hooks (${HOOKS}) fire/g" "$file"
  "${sed_in[@]}" "s/title=\"[0-9]+ Hooks\" href/title=\"${HOOKS} Hooks\" href/g" "$file"
  "${sed_in[@]}" "s/[0-9]+ total: [0-9]+ global hooks, [0-9]+ agent-scoped hooks/${HOOKS} total: ${HOOKS_GLOBAL} global hooks, ${HOOKS_AGENT} agent-scoped hooks/g" "$file"
  "${sed_in[@]}" "s/[0-9]+ active \\([0-9]+ global, [0-9]+ agent,/${HOOKS} active (${HOOKS_GLOBAL} global, ${HOOKS_AGENT} agent,/g" "$file"
  # By-the-numbers table in hooks/overview.mdx — anchor on adjacent rows so we don't hit
  # arbitrary "**Total** | **N**" rows in unrelated tables (analytics, etc.)
  "${sed_in[@]}" "s/\\| \\*\\*Global hooks\\*\\* \\| [0-9]+ \\|/| **Global hooks** | ${HOOKS_GLOBAL} |/g" "$file"
  "${sed_in[@]}" "s/\\| \\*\\*Agent-scoped hooks\\*\\* \\| [0-9]+ \\|/| **Agent-scoped hooks** | ${HOOKS_AGENT} |/g" "$file"
  "${sed_in[@]}" "s/\\| \\*\\*Total\\*\\* \\| \\*\\*[0-9]+\\*\\* \\| Registered in/| **Total** | **${HOOKS}** | Registered in/g" "$file"
}

stamp_docs_mdx() {
  local docs_dir="$PROJECT_ROOT/docs/site/content"
  if [[ ! -d "$docs_dir" ]]; then return; fi

  while IFS= read -r -d '' file; do
    apply_docs_mdx_patterns "$file"
  done < <(find "$docs_dir" -type f -name '*.mdx' -print0)
}

# ── Version sync ────────────────────────────────────────────────────────────
# package.json is the source of truth; propagate to 6 sibling files so a single
# bump stays authoritative. plugins/ork/.claude-plugin/plugin.json is NOT
# touched here — it's regenerated by build-plugins.sh from manifests/ork.json.

sync_versions() {
  local pkg_json="$PROJECT_ROOT/package.json"
  if [[ ! -f "$pkg_json" ]]; then return; fi

  local version
  version=$(jq -r '.version' "$pkg_json")
  if [[ -z "$version" || "$version" == "null" ]]; then
    echo "WARN: could not read version from package.json" >&2
    return
  fi

  local synced=0

  # pyproject.toml — keep the trailing comment
  local pyproject="$PROJECT_ROOT/pyproject.toml"
  if [[ -f "$pyproject" ]]; then
    if [[ "$(uname)" == "Darwin" ]]; then
      sed -i '' -E "s/^version = \"[^\"]+\"( # x-release-please-version)/version = \"${version}\"\\1/" "$pyproject"
    else
      sed -i -E "s/^version = \"[^\"]+\"( # x-release-please-version)/version = \"${version}\"\\1/" "$pyproject"
    fi
    synced=$((synced + 1))
  fi

  # manifests/ork.json — top-level .version
  local ork_manifest="$PROJECT_ROOT/manifests/ork.json"
  if [[ -f "$ork_manifest" ]]; then
    jq --arg v "$version" '.version = $v' "$ork_manifest" > "${ork_manifest}.tmp" && mv "${ork_manifest}.tmp" "$ork_manifest"
    synced=$((synced + 1))
  fi

  # .claude-plugin/marketplace.json — top-level .version AND .plugins[0].version
  local marketplace="$PROJECT_ROOT/.claude-plugin/marketplace.json"
  if [[ -f "$marketplace" ]]; then
    jq --arg v "$version" '.version = $v | (.plugins[0].version) = $v' "$marketplace" > "${marketplace}.tmp" && mv "${marketplace}.tmp" "$marketplace"
    synced=$((synced + 1))
  fi

  # .release-please-manifest.json — .["."]
  local rp_manifest="$PROJECT_ROOT/.release-please-manifest.json"
  if [[ -f "$rp_manifest" ]]; then
    jq --arg v "$version" '."." = $v' "$rp_manifest" > "${rp_manifest}.tmp" && mv "${rp_manifest}.tmp" "$rp_manifest"
    synced=$((synced + 1))
  fi

  # CLAUDE.md — line: - **Current**: X.Y.Z · **Claude Code**: >= ... <!-- x-release-please-version -->
  local claude_md="$PROJECT_ROOT/CLAUDE.md"
  if [[ -f "$claude_md" ]]; then
    if [[ "$(uname)" == "Darwin" ]]; then
      sed -i '' -E "s/(\\*\\*Current\\*\\*: )[0-9]+\\.[0-9]+\\.[0-9]+/\\1${version}/" "$claude_md"
    else
      sed -i -E "s/(\\*\\*Current\\*\\*: )[0-9]+\\.[0-9]+\\.[0-9]+/\\1${version}/" "$claude_md"
    fi
    synced=$((synced + 1))
  fi

  # Note: count is 6 — 5 files touched directly + plugins/ork/.claude-plugin/plugin.json
  # which is regenerated by build-plugins.sh from manifests/ork.json during this same build.
  echo "Version: ${version} synced across 6 sibling files"
}

# ── Check mode ──────────────────────────────────────────────────────────────

if [[ "${1:-}" == "--check" ]]; then
  # Create temp copies, stamp them, diff against originals
  STALE=0
  for file in "${MARKER_FILES[@]}"; do
    if [[ ! -f "$file" ]]; then continue; fi
    TMP=$(mktemp)
    cp "$file" "$TMP"
    stamp_file "$TMP"
    if ! diff -q "$file" "$TMP" >/dev/null 2>&1; then
      echo "STALE: $file"
      STALE=1
    fi
    rm "$TMP"
  done

  # Check marketplace.json
  MKT="$PROJECT_ROOT/.claude-plugin/marketplace.json"
  if [[ -f "$MKT" ]]; then
    TMP=$(mktemp)
    cp "$MKT" "$TMP"
    if [[ "$(uname)" == "Darwin" ]]; then
      sed -i '' -E "s/[0-9]+ skills, [0-9]+ agents, [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, ${HOOKS} hooks/g" "$TMP"
    else
      sed -i -E "s/[0-9]+ skills, [0-9]+ agents, [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, ${HOOKS} hooks/g" "$TMP"
    fi
    if ! diff -q "$MKT" "$TMP" >/dev/null 2>&1; then
      echo "STALE: $MKT"
      STALE=1
    fi
    rm "$TMP"
  fi

  # Check pyproject.toml description count tuple
  PYPROJECT="$PROJECT_ROOT/pyproject.toml"
  if [[ -f "$PYPROJECT" ]]; then
    TMP=$(mktemp)
    cp "$PYPROJECT" "$TMP"
    if [[ "$(uname)" == "Darwin" ]]; then
      sed -i '' -E "s/[0-9]+ skills, [0-9]+ agents, and [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, and ${HOOKS} hooks/g" "$TMP"
    else
      sed -i -E "s/[0-9]+ skills, [0-9]+ agents, and [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, and ${HOOKS} hooks/g" "$TMP"
    fi
    if ! diff -q "$PYPROJECT" "$TMP" >/dev/null 2>&1; then
      echo "STALE: $PYPROJECT"
      STALE=1
    fi
    rm "$TMP"
  fi

  # Check manifests/ork.json description count tuple
  ORK_MANIFEST="$PROJECT_ROOT/manifests/ork.json"
  if [[ -f "$ORK_MANIFEST" ]]; then
    CUR_DESC=$(jq -r '.description' "$ORK_MANIFEST")
    EXP_DESC=$(printf '%s' "$CUR_DESC" | sed -E "s/[0-9]+ skills, [0-9]+ agents, [0-9]+ hooks/${SKILLS} skills, ${AGENTS} agents, ${HOOKS} hooks/g")
    if [[ "$CUR_DESC" != "$EXP_DESC" ]]; then
      echo "STALE: $ORK_MANIFEST (description count)"
      STALE=1
    fi
  fi

  # Check CLAUDE.md plain directory-structure count comment
  CLAUDE_MD_F="$PROJECT_ROOT/CLAUDE.md"
  if [[ -f "$CLAUDE_MD_F" ]]; then
    TMP=$(mktemp)
    cp "$CLAUDE_MD_F" "$TMP"
    if [[ "$(uname)" == "Darwin" ]]; then
      sed -i '' -E "s/# [0-9]+ skills \\(YAML/# ${SKILLS} skills (YAML/g" "$TMP"
    else
      sed -i -E "s/# [0-9]+ skills \\(YAML/# ${SKILLS} skills (YAML/g" "$TMP"
    fi
    if ! diff -q "$CLAUDE_MD_F" "$TMP" >/dev/null 2>&1; then
      echo "STALE: $CLAUDE_MD_F (plain skills count)"
      STALE=1
    fi
    rm "$TMP"
  fi

  # Check docs/site MDX
  DOCS_DIR="$PROJECT_ROOT/docs/site/content"
  if [[ -d "$DOCS_DIR" ]]; then
    while IFS= read -r -d '' file; do
      TMP=$(mktemp)
      cp "$file" "$TMP"
      apply_docs_mdx_patterns "$TMP"
      if ! diff -q "$file" "$TMP" >/dev/null 2>&1; then
        echo "STALE: $file"
        STALE=1
      fi
      rm "$TMP"
    done < <(find "$DOCS_DIR" -type f -name '*.mdx' -print0)
  fi

  if [[ $STALE -eq 1 ]]; then
    echo "Run 'bash scripts/stamp-counts.sh' to fix."
    exit 1
  else
    echo "All counts up to date (${SKILLS} skills, ${AGENTS} agents, ${HOOKS} hooks)."
    exit 0
  fi
fi

# ── Stamp mode (default) ───────────────────────────────────────────────────

for file in "${MARKER_FILES[@]}"; do
  stamp_file "$file"
done

stamp_marketplace_json

stamp_pyproject_description

stamp_ork_manifest_description

stamp_claudemd_plain_count

stamp_docs_mdx

sync_versions

echo "Stamped counts: ${SKILLS} skills, ${AGENTS} agents, ${HOOKS} hooks (${HOOKS_GLOBAL}g + ${HOOKS_AGENT}a + ${HOOKS_SKILL}s), ${INVOCABLE} invocable"
